import sys

def is_airport_code(S, T):
    # Check for case 1: T is a subsequence of S (case-insensitive)
    def is_subsequence(s, t):
        it = iter(s)
        return all(c in it for c in t)

    if is_subsequence(S, T.lower()):
        return True

    # Check for case 2: T[:2] is a subsequence of S and T[2] == 'X'
    if T[2] != 'X':
        return False

    # Check if T[:2] is a subsequence of S (case-insensitive)
    if is_subsequence(S, T[:2].lower()):
        return True

    return False

def main():
    S = sys.stdin.readline().strip()
    T = sys.stdin.readline().strip()
    if is_airport_code(S, T):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
